module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [15:0] carry;
    wire [15:0] sum;
    assign {carry[0], sum[0]} = a[0] + b[0] + Cin;
    genvar i;
    generate
        for (i = 1; i < 16; i = i + 1) begin : adder_gen
            assign {carry[i], sum[i]} = a[i] + b[i] + carry[i - 1];
        end
    endgenerate
    assign y = sum;
    assign Co = carry[15];
endmodule
